from functools import wraps

def vex_reply_filter(policy_id: str):
    def decorator(reply_func):
        @wraps(reply_func)
        def wrapper(message, sender, config):
            # Send reply to Vex for verification
            verification = vex_client.verify_reply(
                policy_id=policy_id,
                content=message["content"],
                context={"agents": [a.name for a in sender.groupchat.agents]},
                use_case="research"
            )

            if not verification.approved:
                return {
                    "content": f"[VEX BLOCKED] {verification.reason}: {message['content'][:100]}...",
                    "role": "assistant",
                    "blocked": True
                }

            # Forward approved reply
            return reply_func(message, sender, config)
        return wrapper
    return decorator

# Apply to group chat manager
manager.reply_func = vex_reply_filter(vex_policy.id)
